class Solution {
public:
    int minimizeXor(int num1, int num2) {
        int set_bits = __builtin_popcount(num2);
        int result = 0;
        int i = 31;
        while (set_bits > 0 && i >= 0) {
            if ((num1 & (1 << i)) == 0) {
                result |= (1 << i);
                set_bits--;
            }
            i--;
        }
        i = 31;
        while (set_bits > 0 && i >= 0) {
            if ((num1 & (1 << i)) != 0) {
                result |= (1 << i);
                set_bits--;
            }
            i--;
        }
        return result;
    }
};
